  ('fire-eq-tech-moex-02877', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '各類場所於增建、改建或變更用途時，其增建或改建部分於「各類場所消防安全設備設置標準」修正條 文施行日起，若僅考量面積因素，按規定樓地板面積合計超過多少以上或佔原建築物總樓地板面積多少 以上時，該建築物之消防安全設備適用增建、改建或變更用途後之標準？', '["1000平方公尺，三分之一", "1000平方公尺，二分之一", "1500平方公尺，三分之一", "1500平方公尺，二分之一"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "a64d4d092471", "answer_pdf_sha1": "465b7400ec13", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
